class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def countNodes(root: TreeNode) -> int:
    if not root:
        return 0

    def get_height_left_path(node):
        h = 0
        while node:
            h += 1
            node = node.left
        return h

    left_height = get_height_left_path(root.left)
    right_height = get_height_left_path(root.right)

    if left_height == right_height:
        return (1 << left_height) + countNodes(root.right)
    else:
        return (1 << right_height) + countNodes(root.left)
